import React,{useRef,useEffect} from 'react'
import Main from '../main/Main'
import './About.scss'
import Slide from 'react-reveal/Slide';
import Pulse from 'react-reveal/Pulse';



const About = () => {

    

    return (
        <div>
            <Main />
            <div id='about'>
            <div className='cover'>
            </div>
            <Pulse right>
                <div   className='about'>
                    <h2 >Who am I</h2>
                    <p >Hi, I am a future Web developer. I have worked in the banking 
                        sector, but I have been interested in programming for a long time.
                        I'm on childcare leave now. It was a good opportunity to learn 
                        and acquire a new profession. I'm always in for learning new stuff,  
                        seeking to improve and grow as a professional and as a person. I enjoy 
                        solving complex problems. I am energetic and imaginative young web developer 
                        who is able to work alongside other talented IT professionals in creating 
                        websites. Right now I am looking for a internship position or an entry level 
                        position with an exciting company.
                </p>
                </div>
            </Pulse>
            <div className='bgImage'>
            </div>
            </div>
        </div>
    )
}
export default About